-- Not normalized: employee data with department info mixed in
CREATE TABLE not_normalized (
  emp_id INT,
  emp_name VARCHAR(100),
  dept_name VARCHAR(50),  -- repeated for every employee in dept
  dept_location VARCHAR(50)  -- also repeated
);

-- Normalized: separate tables
CREATE TABLE departments (
  dept_id INT PRIMARY KEY,
  dept_name VARCHAR(50),
  location VARCHAR(50)
);

CREATE TABLE employees (
  emp_id INT PRIMARY KEY,
  emp_name VARCHAR(100),
  dept_id INT REFERENCES departments(dept_id)
);

