-- Violates 1NF: multiple phone numbers in one column
CREATE TABLE violates_1nf (
  employee_id INT,
  name VARCHAR(100),
  phone_numbers VARCHAR(200)  -- '555-0100,555-0101,555-0102'
);

-- 1NF Compliant: separate row per phone number
CREATE TABLE employee_phones (
  employee_id INT,
  phone_number VARCHAR(20),
  PRIMARY KEY (employee_id, phone_number)
);

-- Before normalization: transitive dependency
CREATE TABLE employee_projects_bad (
  emp_id INT,
  project_id INT,
  emp_name VARCHAR(100),  -- depends only on emp_id
  project_name VARCHAR(100),  -- depends only on project_id
  hours_worked INT,  -- depends on both emp_id AND project_id
  PRIMARY KEY (emp_id, project_id)
);

-- After normalization to 3NF
CREATE TABLE employees (
  emp_id INT PRIMARY KEY,
  emp_name VARCHAR(100)
);

CREATE TABLE projects (
  project_id INT PRIMARY KEY,
  project_name VARCHAR(100)
);

CREATE TABLE assignments (
  emp_id INT REFERENCES employees(emp_id),
  project_id INT REFERENCES projects(project_id),
  hours_worked INT,
  PRIMARY KEY (emp_id, project_id)
);

